const emailData = items[0].json;

// Extract sender safely
let sender = "Unknown";
if (emailData.from?.value?.[0]?.address) {
  sender = emailData.from.value[0].address;
} else if (emailData.from) {
  sender = emailData.from;
}

// Extract subject safely
let subject = "Unknown";
if (emailData.subject) {
  subject = emailData.subject;
} else if (emailData.headers) {
  const subjectHeader = emailData.headers.find(h => h.name === "Subject");
  if (subjectHeader) subject = subjectHeader.value;
}

// Extract email body
const bodyText = emailData.textPlain || emailData.text || "";
const bodyHtml = emailData.html || "";

// Extract links
const linkRegex = /https?:\/\/[^\s<>"]+/gi;
const textLinks = bodyText.match(linkRegex) || [];
const htmlLinks = bodyHtml.match(linkRegex) || [];
const links = [...new Set([...textLinks, ...htmlLinks])];

// Attachments
const attachments = emailData.attachments || [];
const hasAttachments = attachments.length > 0;

// Clean body for AI analysis
const bodyForAnalysis = (bodyText || bodyHtml.replace(/<[^>]*>/g, " "))
  .replace(/\s+/g, " ")
  .trim()
  .substring(0, 1200);

return [
{
json: {
sender,
subject,
bodyText,
bodyHtml,
bodyForAnalysis,
attachments,
hasAttachments,
links,
messageId: emailData.id || "",
threadId: emailData.threadId || "",
receivedDate: emailData.date || new Date().toISOString()
}
}
];

const emailData = items[0].json;
let attachmentText = '';
const processedAttachments = [];

if (emailData.attachments && emailData.attachments.length > 0) {
  for (const attachment of emailData.attachments) {
    const processed = {
      filename: attachment.filename || 'unknown',
      contentType: attachment.contentType || 'unknown',
      size: attachment.size || 0,
      textExtracted: false,
      extractedText: ''
    };

    if (attachment.contentType) {
      if (attachment.contentType.includes('text/')) {
        processed.extractedText = 'Text file content available';
        processed.textExtracted = true;
      } else if (attachment.contentType.includes('pdf')) {
        processed.extractedText = 'PDF attachment detected - text extraction requires additional service';
        processed.textExtracted = false;
      } else if (attachment.contentType.includes('word') || attachment.contentType.includes('document')) {
        processed.extractedText = 'Word document detected - text extraction requires additional service';
        processed.textExtracted = false;
      }
    }

    processedAttachments.push(processed);

    if (processed.textExtracted) {
      attachmentText += `\n[Attachment: ${processed.filename}] ${processed.extractedText}`;
    }
  }
}

const combinedContent = emailData.bodyForAnalysis + attachmentText;

return [{
  json: {
    ...emailData,
    processedAttachments,
    combinedContent: combinedContent.substring(0, 1500),
    attachmentProcessingComplete: true
  }
}];

const emailData = items[0].json;

return [{
  json: {
    ...emailData,
    processedAttachments: [],
    combinedContent: emailData.bodyForAnalysis,
    attachmentProcessingComplete: true
  }
}];

const aiData = items[0].json;
const aiResponse = aiData.output || aiData;

const validActions = ["Reply Needed", "Review Attachment", "Task Required", "Meeting Scheduled", "For Your Information"];
const callToAction = aiResponse.callToAction || aiResponse.action_required || "For Your Information";

const emailData = $("Extract Email Data").first().json;

return [{
json: {
sender: emailData.sender,
subject: emailData.subject,
bodyForAnalysis: emailData.bodyForAnalysis,
attachments: emailData.attachments,
links: emailData.links,
summary: aiResponse.summary || "No summary",
priority: aiResponse.priority || "Medium",
action_required: validActions.includes(callToAction) ? callToAction : "For Your Information",
task: aiResponse.task || "",
meeting: aiResponse.meeting || "",
deadline: aiResponse.deadline || "",
insights: aiResponse.insights || "",
timestamp: new Date().toISOString(),
aiAnalysis: aiResponse
}
}];

